sql:
SELECT dataset_id, data_file, version 
FROM datasets 
WHERE subject_id = 0;

SELECT user_name, institution 
FROM users 
WHERE user_id BETWEEN 0 AND 5;

SELECT dataset_id, data_file
FROM datasets
WHERE experiment_id = 1;

external_knowledge:
- 'dataset_id = 0' refers to the first or initial dataset;
- 'download' indicates the action of downloading the dataset;
- 'individuals' corresponds to 'subject_name' in the context.

sql:
SELECT datasets.dataset_id, subjects.subject_name, subjects.age
FROM datasets
INNER JOIN subjects ON datasets.subject_id = subjects.subject_id;

SELECT COUNT(DISTINCT data_type) AS sprouted_seeds
FROM datasets
WHERE condition = 0;
